---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"div"> {
  defaultValue?: string
  orientation?: "horizontal" | "vertical"
  activationMode?: "auto" | "manual"
}

const {
  class: className,
  defaultValue,
  orientation = "horizontal",
  activationMode,
  ...props
} = Astro.props
---

<div
  data-slot="tabs"
  data-default-value={defaultValue}
  data-orientation={orientation}
  data-horizontal={orientation === "horizontal" ? "" : undefined}
  data-vertical={orientation === "vertical" ? "" : undefined}
  data-activation-mode={activationMode}
  class={cn("group/tabs flex gap-2 data-horizontal:flex-col", className)}
  {...props}
>
  <slot />
</div>

<script>
  import { createTabs } from "@data-slot/tabs"

  document.querySelectorAll("[data-slot='tabs']").forEach((el) => {
    createTabs(el)
  })
</script>

---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const tabsListVariants = cva(
  "group/tabs-list text-muted-foreground inline-flex w-fit items-center justify-center rounded-lg p-[3px] group-data-horizontal/tabs:h-9 group-data-vertical/tabs:h-fit group-data-vertical/tabs:flex-col data-[variant=line]:rounded-none",
  {
    variants: {
      variant: {
        default: "bg-muted",
        line: "gap-1 bg-transparent",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

interface Props
  extends HTMLAttributes<"div">,
    VariantProps<typeof tabsListVariants> {}

const { class: className, variant = "default", ...props } = Astro.props
---

<div
  data-slot="tabs-list"
  data-variant={variant}
  role="tablist"
  class={cn(tabsListVariants({ variant }), className)}
  {...props}
>
  <slot />
</div>
